## Code Example
```javascript
function evaluatePDP(tenantId, metadata, policies) {
  const policy = policies[tenantId] || policies["default"];
  // residency check
  if (policy.residency && policy.residency !== metadata.region) return { action: "block" };
  // budget constraint
  if (typeof policy.budget === "number" && metadata.cost > policy.budget) return { action: "redirect", destination: "onPrem" };
  // allowed destination
  if (policy.allowedDestinations?.includes("OpenAI")) return { action: "allow", destination: "OpenAI" };
  return { action: "block" };
}
```

