// Pseudocode: compute final answer with grounding and provenance
async function answer(query) {
  const docs = await searchKB(query);
  const prompt = buildPrompt(query, docs);
  const res = await openai.complete({ prompt });
  const provenance = docs.map(d => d.id);
  const confidence = res.meta?.confidence ?? 0.9;
  if (confidence < 0.8) await ticketSystem.create('Review needed', { query, provenance });
  return { text: res.text, confidence, provenance };
}
